sp_widget.client_script:
api.controller=function($scope, spUtil,$timeout) {

  var c = this;


  /*c.saveDisplayNames = function(){

    c.data.action = "saveDisplayNames";
    c.data.quarters = c.data.quarters;

    c.server.update().then(function(){

      spUtil.addInfoMessage("Display Names Saved");
    });

  }; */

	c.saveDisplayNames = function(){

		c.data.action = "saveDisplayNames";
		c.data.calendar_sys_id = c.data.calId;
		c.data.quarters = c.data.quarters;

		c.server.update().then(function(res){

			if (res.data && res.data.quarters) {
				c.data.quarters = res.data.quarters;
					}
			c.editMode = false;

			//spUtil.addInfoMessage("Display Names Saved");
			c.successMessage = "Display Names Saved";

	$timeout(function(){
  c.successMessage = "";
}, 3000);


			});

		};

};

sp_widget.css:
.btn-primary
{
	background: #000000;
}
.fiscal-container{
  border:1px solid #dcdcdc;
  padding:20px;
  /*margin-top:20px; */
  background: #ffffff;
}

.quarter-box{
  border:1px solid #dcdcdc;
  padding:10px;
  background:#fafafa;
  min-height:220px;
}

.quarter-header{
  display:flex;
  justify-content:space-between;
  align-items:center;
  margin-bottom:15px;
}

.quarter-input{
  width:120px;
}

.month-row{
  display:flex;
  justify-content:space-between;
  align-items:center;
  margin-bottom:10px;
}

.month-input{
  width:120px;
}

.action-buttons{
  margin-top:20px;
}

.edit-toggle{
  display:flex;
  align-items:center;
  margin-bottom:15px;
}

.toggle-label{
  margin-left:10px;
  font-weight:600;
}

/* Switch */

.switch {
  position: relative;
  display: inline-block;
  width: 45px;
  height: 22px;
}

.switch input {
  opacity: 0;
  width: 0;
  height: 0;
}

.slider {
  position: absolute;
  cursor: pointer;
  background-color: #ccc;
  border-radius: 22px;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  transition: .3s;
}

.slider:before {
  position: absolute;
  content: "";
  height: 18px;
  width: 18px;
  left: 2px;
  bottom: 2px;
  background-color: white;
  border-radius: 50%;
  transition: .3s;
}

input:checked + .slider {
  background-color: #1f8476;
}

input:checked + .slider:before {
  transform: translateX(22px);
}

.fiscal-header{
  display:flex;
  justify-content:space-between;
  align-items:center;
  width:100%;
}

.panel-title{
  margin:0;
  flex:1;
}

/*.edit-toggle{
  display:flex;
  align-items:center;
  gap:10px;
}*/

.toggle-text{
  font-weight:600;
  //font-size:13px;
}


.alert {
  text-align: left !important;
}

sp_widget.script:
(function() {
  /* populate the 'data' object */
  /* e.g., data.table = $sp.getValue('table'); */

		if (input && input.calendar_sys_id) 
			{
				//gs.addErrorMessage(" I have come as input "+input.calendar_sys_id);
  			data.calId = input.calendar_sys_id;
			} else if (!data.calId) {
								//gs.addErrorMessage(" I have come as data "+options.calendar_sys_id+ " -- "+ $sp.getParameter("sys_id"));
				data.calId = options.calendar_sys_id || $sp.getParameter("sys_id") || "";
			}
	data.table=options.table || $sp.getParameter('table') || "";
	data.isApplicationAdmin= gs.getUser().hasRole('x_ctans_incentnow.admin');

	/*data.quarters = [
  {
    name: "Q1 2026",
    months: ["January","February","March"]
  },
  {
    name: "Q2 2026",
    months: ["April","May","June"]
  },
  {
    name: "Q3 2026",
    months: ["July","August","September"]
  },
  {
    name: "Q4 2026",
    months: ["October","November","December"]
  }
]; */

	isFiscalPeriodExist();
	function isFiscalPeriodExist()
	{
		data.fiscalExist=false;
		var fiscalPeriod = new GlideRecordSecure("x_ctans_incentnow_fiscal_period");
		if(fiscalPeriod.get("fiscal_year",data.calId)){
			data.fiscalExist=true;
		}
	}

	if(input && input.action == "saveDisplayNames"){

		//gs.addErrorMessage("hello")

	var quarters = input.quarters;
		//gs.addInfoMessage("JSON.stringify(quarters) "+ input.action + " -- "+input.calendar_sys_id);

	for(var i=0;i<quarters.length;i++){

		var q = quarters[i];
		//gs.addInfoMessage(JSON.stringify(q));

		// update quarter
		var gQuarter = new GlideRecordSecure("x_ctans_incentnow_fiscal_period");
		if(gQuarter.get(q.sys_id)){
			gQuarter.period_display_name = q.period_display_name;
			gQuarter.update();
		}

		// update months
		for(var j=0;j<q.months.length;j++){

			var m = q.months[j];

			var gMonth = new GlideRecordSecure("x_ctans_incentnow_fiscal_period");
			if(gMonth.get(m.sys_id)){
				gMonth.period_display_name = m.period_display_name;
				gMonth.update();
			}

		}
	}

	data.status="saved";

}

	data.quarters=getFiscalCalendar();

	function getFiscalCalendar() {

	var quarters = [];
	var quarterMap = {};

	// GET ALL QUARTERS
	var q = new GlideRecordSecure("x_ctans_incentnow_fiscal_period");
	//gs.addErrorMessage("fiscal year "+data.calId);
	q.addQuery("fiscal_year", data.calId);
	q.addQuery("period_type", "quarter");
	q.orderBy("period_number");
	q.query();

	while(q.next()) {

		var obj = {
			sys_id: q.getUniqueValue(),
			name: q.getValue("period_name"),
			period_display_name: q.getValue("period_display_name"),
			months: []
		};

		quarterMap[q.getUniqueValue()] = obj;
		quarters.push(obj);
	}

	//  GET ALL MONTHS
	var m = new GlideRecordSecure("x_ctans_incentnow_fiscal_period");
	m.addQuery("fiscal_year", data.calId);
	m.addQuery("period_type", "month");
	m.orderBy("period_number");
	m.query();

	while(m.next()) {

		var parent = m.getValue("parent_period");

		if(quarterMap[parent]) {

			quarterMap[parent].months.push({
				sys_id: m.getUniqueValue(),
				name: m.getValue("period_name"),
				period_display_name: m.getValue("period_display_name")
			});

		}
	}

	return quarters;
}


})();
